static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
  Value *X, *Cond;

  // Match llvm.fabs intrinsic or select-based fabs pattern.
  // For select-based fabs, both arms compare identically with zero,
  // regardless of the condition (since fneg only flips sign, and -0.0 == 0.0).
  if (match(I.getOperand(0), m_FAbs(m_Value(X)))) {
    // fall through
  } else if (match(I.getOperand(0),
                   m_Select(m_Value(Cond), m_Value(X), m_FNeg(m_Deferred(X)))) ||
             match(I.getOperand(0),
                   m_Select(m_Value(Cond), m_FNeg(m_Value(X)), m_Deferred(X)))) {
    // Matched select-based fabs: either (select cond, X, fneg X) or
    // (select cond, fneg X, X). Both compute the same set of possible values,
    // and comparing with zero gives the same result for both arms.
  } else {
    return nullptr;
  }
